 1	import * as React from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import OwnerReferences from '@kubevirt-utils/components/OwnerReferences/OwnerReferences';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Breadcrumb,
 9	  BreadcrumbItem,
10	  DescriptionListDescription,
11	  DescriptionListGroup,
12	  DescriptionListTermHelpText,
13	  DescriptionListTermHelpTextButton,
14	  Popover,
15	} from '@patternfly/react-core';
16	
17	type OwnerDetailsItemProps = {
18	  obj: K8sResourceCommon;
19	};
20	
21	const OwnerDetailsItem: React.FC<OwnerDetailsItemProps> = ({ obj }) => {
22	  const { t } = useKubevirtTranslation();
23	
24	  return (
25	    <DescriptionListGroup className="pf-v6-c-description-list__group">
26	      <DescriptionListTermHelpText className="pf-v6-c-description-list__term">
27	        <Popover
28	          bodyContent={
29	            <Trans ns="plugin__kubevirt-plugin">
30	              <div>
31	                List of objects depended by this object. If ALL objects in the list have been
32	                deleted, this object will be garbage collected. If this object is managed by a
33	                controller, then an entry in this list will point to this controller, with the
34	                controller field set to true. There cannot be more than one managing controller.
35	              </div>
36	              <Breadcrumb className="margin-top">
37	                <BreadcrumbItem>{{ kind: obj?.kind }}</BreadcrumbItem>
38	                <BreadcrumbItem>metadata</BreadcrumbItem>
39	                <BreadcrumbItem>ownerReferences</BreadcrumbItem>
40	              </Breadcrumb>
41	            </Trans>
42	          }
43	          hasAutoWidth
44	          headerContent={t('Owner')}
45	          maxWidth="30rem"
46	        >
47	          <DescriptionListTermHelpTextButton className="pf-v6-c-description-list__text">
48	            {t('Owner')}
49	          </DescriptionListTermHelpTextButton>
50	        </Popover>
51	      </DescriptionListTermHelpText>
52	      <DescriptionListDescription className="pf-v6-c-description-list__description">
53	        <OwnerReferences obj={obj} />
54	      </DescriptionListDescription>
55	    </DescriptionListGroup>
56	  );
57	};
58	
59	export default OwnerDetailsItem;

